#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $cgi = CGI->new;

# Get the comment from parameters, escape HTML entities to prevent XSS
my $comment = $cgi->param('comment') // '';
$comment =~ s/</&lt;/g;
$comment =~ s/>/&gt;/g;

print "Content-type: text/html\n\n";
print "<div>$comment</div>";